function c(t,n){if(t==null||t==="")return"";const r=parseFloat(t);if(!n||!n.secondary_unit||!n.secondary_unit_ratio)return`${r} ${n?.unit||n?.adhoc_unit||""}`.trim();const o=parseFloat(n.secondary_unit_ratio);if(!o||o<=0)return`${r} ${n.unit||n.adhoc_unit||""}`.trim();const a=Math.floor(r/o),u=r%o;let s="";if(a>0&&(s+=`${a} ${n.secondary_unit} `),u>0||a===0&&u===0){const i=Number(u.toFixed(2));s+=`${i} ${n.unit||""}`}return s.trim()}export{c as f};
